import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
interface Q { tier:string; exam:string; stem:string; options:string[]; correct:number; rationale:string; diff:number; bs:string; }

function rpn(exam:string,bs:string,diff:number,stem:string,opts:string[],c:number,rat:string):Q { return {tier:"rpn",exam,stem,options:opts,correct:c,rationale:rat,diff,bs}; }
function rn(exam:string,bs:string,diff:number,stem:string,opts:string[],c:number,rat:string):Q { return {tier:"rn",exam,stem,options:opts,correct:c,rationale:rat,diff,bs}; }
function np(exam:string,bs:string,diff:number,stem:string,opts:string[],c:number,rat:string):Q { return {tier:"np",exam,stem,options:opts,correct:c,rationale:rat,diff,bs}; }

const ALL: Q[] = [
  // === RPN ADDITIONAL (need ~554 more to reach 3000) ===
  rpn("REX-PN","Cardiovascular",3,"A client with unstable angina is placed on IV heparin and oral aspirin. The nurse monitors for bleeding because these medications:",["Increase cardiac output","Both inhibit clot formation through different mechanisms","Cause vasoconstriction","Increase platelet production"],1,"Heparin inhibits clotting factors while aspirin inhibits platelet aggregation. Together they significantly increase bleeding risk. The nurse monitors for signs of bleeding including bruising, petechiae, blood in stool/urine, and gum bleeding."),
  rpn("REX-PN","Cardiovascular",3,"The nurse evaluates the effectiveness of compression stockings. Which finding indicates proper function?",["The stockings cause numbness and tingling","Decreased peripheral edema in the lower extremities","Increased redness of the feet","Stockings feel loose around the calves"],1,"Compression stockings promote venous return and reduce peripheral edema. Proper fit is essential - they should be snug but not cause numbness. They should be applied before getting out of bed and removed for bathing and skin inspection."),
  rpn("REX-PN","Cardiovascular",2,"A client asks why they need to take aspirin daily after a stent placement. The nurse explains that aspirin:",["Dissolves the stent gradually","Prevents platelet aggregation and stent thrombosis","Reduces cholesterol levels","Strengthens the stent"],1,"After stent placement, dual antiplatelet therapy (aspirin + clopidogrel or ticagrelor) prevents stent thrombosis, which can cause myocardial infarction. Aspirin inhibits cyclooxygenase, reducing thromboxane A2 and platelet aggregation."),
  rpn("RPN-CAT","Cardiovascular",3,"A client with peripheral arterial disease should be instructed to:",["Soak feet in hot water nightly","Avoid crossing the legs and stop smoking","Apply constrictive stockings","Elevate legs above heart level at all times"],1,"Smoking cessation is the most important modifiable risk factor for PAD. Avoiding leg crossing prevents further impairment of already compromised arterial circulation. Feet should be kept warm but not with hot water due to reduced sensation."),
  rpn("REX-PN","Cardiovascular",3,"After open heart surgery, a client has a mediastinal chest tube draining 200 mL/hour of sanguineous fluid. The nurse should:",["Document and continue monitoring","Notify the surgeon immediately as this exceeds normal drainage","Clamp the chest tube","Milk the chest tube vigorously"],1,"Normal mediastinal drainage post-cardiac surgery is 100-200 mL in the first hour, decreasing to < 50 mL/hour. Drainage of 200 mL/hour after the initial period suggests active bleeding requiring surgical evaluation and possible re-exploration."),
  rpn("REX-PN","Respiratory",3,"A client with cystic fibrosis is prescribed pancreatic enzyme replacement. The nurse instructs the client to take these:",["At bedtime only","With meals and snacks","On an empty stomach one hour before eating","Only when experiencing diarrhea"],1,"Pancreatic enzyme supplements replace deficient enzymes needed for fat and protein digestion. They should be taken with all meals and snacks to aid digestion and nutrient absorption. Capsules should not be crushed as the enteric coating protects them from gastric acid."),
  rpn("REX-PN","Respiratory",2,"A client is admitted with bacterial pneumonia. Which intervention helps prevent the spread of the infection?",["Placing the client in a private room with negative pressure","Encouraging coughing into the elbow or a tissue","Restricting all visitors indefinitely","Keeping the room temperature below 18C"],1,"Respiratory hygiene/cough etiquette (covering the mouth when coughing, using tissues, hand hygiene) is essential for preventing pneumonia transmission. Standard precautions apply to most bacterial pneumonia, with droplet precautions for specific organisms."),
  rpn("RPN-CAT","Respiratory",3,"A client with emphysema has barrel-shaped chest on physical examination. This occurs because of:",["Fluid accumulation in the pleural space","Chronic air trapping causing hyperinflation of the lungs","Chest wall muscle hypertrophy","Pectus excavatum"],1,"Chronic air trapping in emphysema increases the anteroposterior diameter of the chest, creating a barrel-shaped appearance. The diaphragm flattens, and accessory muscles are used for breathing. This is a late finding indicating advanced disease."),
  rpn("REX-PN","Respiratory",3,"When caring for a client receiving oxygen therapy, the nurse should prioritize:",["Keeping all oxygen equipment away from electrical outlets","Posting no-smoking signs and removing spark-producing devices","Using petroleum-based products for nasal dryness","Storing oxygen tanks near heat sources for warming"],1,"Oxygen supports combustion, creating a fire risk. No-smoking signs, removing spark sources, using water-based lubricants (not petroleum), and keeping oxygen away from heat sources are essential safety measures."),
  rpn("REX-PN","Respiratory",2,"A client with influenza asks about antiviral medication. The nurse explains that oseltamivir is most effective when started within:",["24 hours of symptom onset","48 hours of symptom onset","72 hours of symptom onset","1 week of symptom onset"],1,"Oseltamivir (Tamiflu) is most effective when initiated within 48 hours of influenza symptom onset. It reduces symptom duration by 1-2 days and decreases complications. It may still be beneficial after 48 hours in hospitalized or high-risk patients."),
  rpn("REX-PN","Neurological",3,"A client with increased intracranial pressure has Cushing triad. This includes:",["Tachycardia, hypotension, and rapid breathing","Hypertension, bradycardia, and irregular respirations","Fever, tachycardia, and diaphoresis","Hypotension, tachycardia, and Cheyne-Stokes breathing"],1,"Cushing triad (hypertension, bradycardia, irregular/widening pulse pressure respirations) is a late sign of brainstem herniation from critically elevated ICP. It requires immediate intervention to reduce ICP and prevent death."),
  rpn("REX-PN","Neurological",2,"A client is prescribed levodopa for Parkinson disease. The nurse should instruct the client to avoid taking the medication with:",["Water","High-protein meals","Crackers","Applesauce"],1,"High-protein meals compete with levodopa for absorption in the small intestine, reducing its effectiveness. Protein should be distributed throughout the day or taken separately from levodopa. The medication should be taken 30 minutes before or 1 hour after meals."),
  rpn("RPN-CAT","Neurological",3,"A client post-craniotomy develops diabetes insipidus. The nurse identifies this complication by:",["Decreased urine output and edema","Excessive urination with very dilute urine","Weight gain and hypertension","Decreased thirst and concentrated urine"],1,"Post-craniotomy DI results from damage to the posterior pituitary or hypothalamus, reducing ADH secretion. Signs include polyuria (up to 20 L/day), very dilute urine (specific gravity < 1.005), excessive thirst, and hypernatremia."),
  rpn("REX-PN","Neurological",3,"A client with a right hemispheric stroke has left-sided neglect. The nurse should:",["Approach the client from the left side only","Place items on the client's right side initially and teach scanning techniques","Ignore the left side during care","Move all furniture to the left side"],1,"Left-sided neglect means the client is unaware of the left visual field and body. Initially place items on the right (unaffected) side, then gradually teach the client to scan left to promote awareness and rehabilitation of the neglected side."),
  rpn("REX-PN","Endocrine",3,"A client with Cushing syndrome should be monitored for:",["Hypoglycemia and weight loss","Hyperglycemia and increased infection risk","Hypothermia and bradycardia","Hypotension and dehydration"],1,"Excess cortisol in Cushing syndrome causes hyperglycemia (gluconeogenesis), immunosuppression (increased infection risk), hypertension, sodium/water retention, muscle wasting, osteoporosis, and central obesity with moon face and buffalo hump."),
  rpn("RPN-CAT","Endocrine",3,"A client with diabetes mellitus develops diabetic ketoacidosis. The nurse should anticipate which IV fluid for initial resuscitation?",["Dextrose 5% in water","0.9% Normal Saline","Dextrose 10% in half normal saline","Lactated Ringer's solution"],1,"Initial fluid resuscitation in DKA uses 0.9% Normal Saline (isotonic) to expand intravascular volume and correct dehydration. Typically 1-2 liters in the first hour. Once glucose drops to 200-250 mg/dL, dextrose-containing fluids are added."),
  rpn("REX-PN","Endocrine",2,"A client taking oral hypoglycemic medications should be taught to recognize early signs of hypoglycemia, which include:",["Polyuria and polydipsia","Trembling, sweating, and confusion","Fruity breath and deep rapid breathing","Dry skin and weight loss"],1,"Early hypoglycemia signs result from sympathetic nervous system activation: trembling, sweating, tachycardia, anxiety, and hunger. Neuroglycopenic symptoms (confusion, slurred speech, seizures, loss of consciousness) occur as glucose drops further."),
  rpn("REX-PN","Gastrointestinal",3,"A client with Crohn disease is most likely to have involvement of which area?",["The rectum only","The terminal ileum","The sigmoid colon only","The esophagus"],1,"Crohn disease most commonly affects the terminal ileum and can involve any part of the GI tract from mouth to anus. It has skip lesions (healthy tissue between affected areas), transmural inflammation, and may cause fistulas and strictures."),
  rpn("REX-PN","Gastrointestinal",2,"A client after a cholecystectomy should follow which dietary guideline?",["High-fat diet for energy","Low-fat diet initially, gradually increasing fat intake","Liquid diet for one month","No dietary changes needed"],1,"After cholecystectomy, bile drips continuously into the duodenum rather than being stored and concentrated. A low-fat diet initially allows the body to adapt. Fat intake can be gradually increased as tolerated over several weeks."),
  rpn("RPN-CAT","Gastrointestinal",3,"A client with a bowel obstruction has projectile vomiting of fecal material. This suggests:",["Early small bowel obstruction","Complete large bowel or late small bowel obstruction","Gastric ulcer perforation","Mild constipation"],1,"Feculent vomiting indicates late or distal obstruction where intestinal contents have been stagnant long enough for bacterial overgrowth to produce fecal-smelling material. This is a surgical emergency requiring decompression and possible operative intervention."),
  rpn("REX-PN","Pharmacology",3,"A client is prescribed enoxaparin subcutaneously. The nurse should:",["Aspirate before injecting to check for blood return","Inject into the abdomen without aspirating and do not rub the site","Administer the injection intramuscularly","Massage the injection site vigorously afterward"],1,"Low molecular weight heparin (enoxaparin) is given subcutaneously in the abdomen. Do not aspirate before or massage after injection as this causes bruising. Rotate injection sites. Hold the skin fold throughout the injection."),
  rpn("REX-PN","Pharmacology",2,"A client asks about the difference between acetaminophen and ibuprofen. The nurse explains that unlike ibuprofen, acetaminophen:",["Has anti-inflammatory properties","Does not have anti-inflammatory properties","Is an anticoagulant","Requires a prescription"],1,"Acetaminophen is an analgesic and antipyretic but lacks anti-inflammatory properties. Ibuprofen (NSAID) provides analgesia, antipyretic, and anti-inflammatory effects. Acetaminophen is preferred for patients who cannot take NSAIDs (GI bleeding, renal disease, anticoagulant use)."),
  rpn("RPN-CAT","Pharmacology",3,"A client on lithium therapy should maintain adequate intake of:",["Calcium","Sodium and fluids","Potassium","Iron"],1,"Lithium is reabsorbed in the proximal tubule alongside sodium. Sodium depletion or dehydration causes increased lithium reabsorption and toxicity. Clients must maintain consistent sodium and fluid intake, avoiding drastic dietary changes, excessive sweating, and dehydrating illness."),
  rpn("REX-PN","Pharmacology",3,"A client taking isoniazid (INH) for tuberculosis should receive supplemental:",["Vitamin A","Vitamin B6 (pyridoxine)","Vitamin C","Vitamin D"],1,"INH depletes pyridoxine (vitamin B6), causing peripheral neuropathy. Supplemental B6 (25-50 mg daily) prevents this adverse effect. Other INH side effects include hepatotoxicity (monitor liver enzymes) and drug interactions with phenytoin."),
  rpn("REX-PN","Mental Health",3,"A client in a manic episode has not slept in 3 days and is spending money recklessly. The priority nursing diagnosis is:",["Self-care deficit","Risk for injury","Social isolation","Impaired verbal communication"],1,"During manic episodes, clients have impaired judgment, hyperactivity, decreased need for sleep, and engage in risky behavior (spending, sexual indiscretions, dangerous activities). Risk for injury is the priority due to poor decision-making and exhaustion."),
  rpn("REX-PN","Mental Health",2,"The nurse uses the CAGE questionnaire to screen for:",["Depression","Alcohol use disorder","Anxiety disorder","Eating disorders"],1,"CAGE is a validated alcohol screening tool: Cut down (felt need to?), Annoyed (by criticism?), Guilty (about drinking?), Eye-opener (drink in morning?). Two or more positive answers suggest alcohol use disorder requiring further assessment."),
  rpn("RPN-CAT","Mental Health",3,"A client taking a benzodiazepine for anxiety reports tolerance and increasing the dose without provider approval. The nurse should:",["Encourage the client to continue the increased dose","Educate about the risks and report to the provider immediately","Suggest switching to a different benzodiazepine","Tell the client to stop the medication abruptly"],1,"Self-increasing benzodiazepine doses indicates tolerance and potential dependence. The provider must be notified for proper assessment and management. Abrupt discontinuation of benzodiazepines can cause seizures and is potentially fatal."),
  rpn("REX-PN","Pediatrics",3,"A child with acute lymphoblastic leukemia has a WBC of 90,000/mm3. The nurse should monitor for:",["Iron deficiency anemia only","Tumor lysis syndrome and leukostasis","Immediate remission","Increased platelet production"],1,"Very high WBC counts cause leukostasis (WBC plugging blood vessels) and tumor lysis syndrome when chemotherapy kills massive numbers of cells. Monitor for altered mental status, respiratory distress, hyperkalemia, hyperuricemia, and renal failure."),
  rpn("REX-PN","Pediatrics",2,"When assessing an infant's fontanelles, a bulging anterior fontanelle may indicate:",["Dehydration","Increased intracranial pressure","Normal finding in a crying infant","Malnutrition"],1,"A bulging fontanelle (when the infant is calm and upright) indicates increased intracranial pressure from conditions such as meningitis, hydrocephalus, or intracranial hemorrhage. A sunken fontanelle indicates dehydration. Bulging during crying is normal."),
  rpn("RPN-CAT","Pediatrics",3,"A child with suspected meningitis is positioned for a lumbar puncture. The nurse should:",["Position the child sitting upright with head extended","Position the child in a lateral recumbent position with knees drawn to chest","Position the child prone with a pillow under the abdomen","Allow the child to choose the most comfortable position"],1,"Lateral recumbent (side-lying) position with knees drawn to chest and chin tucked opens the intervertebral spaces for needle insertion. The nurse holds the child securely to prevent movement while monitoring respiratory status and providing comfort."),
  rpn("REX-PN","Pediatrics",2,"The nurse is teaching a parent about introducing solid foods to an infant. Solid foods should be introduced at approximately:",["2 months of age","4-6 months of age","8-10 months of age","12 months of age"],1,"Solid foods are introduced at 4-6 months when developmental readiness signs appear: good head control, sitting with support, loss of tongue thrust reflex, and showing interest in food. Start with iron-fortified cereal, then single-ingredient purees."),
  rpn("REX-PN","Fundamentals",3,"A client's central venous catheter site appears red and has purulent drainage. The nurse suspects:",["Normal healing response","Catheter-related bloodstream infection","Allergic reaction to the dressing","Expected postinsertion inflammation"],1,"Redness and purulent drainage at a central line site indicate possible catheter-related infection. The nurse should obtain blood cultures (from the catheter and peripheral site), notify the provider, and anticipate catheter removal and antibiotic therapy."),
  rpn("REX-PN","Fundamentals",2,"When caring for a client with a peripheral IV, the nurse should change the IV site every:",["24 hours","48-72 hours","72-96 hours","7 days"],2,"CDC guidelines recommend peripheral IV catheter replacement every 72-96 hours to reduce the risk of phlebitis and catheter-related infection. The site should also be changed if signs of infiltration, phlebitis, or infection develop."),
  rpn("RPN-CAT","Fundamentals",3,"A client receiving enteral feeding through an NG tube develops aspiration pneumonia. To prevent recurrence, the nurse should:",["Administer feedings with the client flat","Verify tube placement before each feeding and keep HOB elevated 30-45 degrees","Increase the feeding rate","Use only water for tube feedings"],1,"Aspiration prevention includes verifying tube placement (pH testing, X-ray), elevating HOB 30-45 degrees during and 30-60 minutes after feeding, checking gastric residual volumes, and using continuous rather than bolus feedings when appropriate."),
  rpn("REX-PN","Musculoskeletal",3,"A client with a newly applied fiberglass cast reports a burning sensation under the cast. The nurse understands this is caused by:",["An allergic reaction to the cast material","An exothermic reaction during the curing process","Compartment syndrome developing","Infection under the cast"],1,"Fiberglass casts generate heat during the chemical curing process (exothermic reaction). This is a normal, temporary finding. The nurse should reassure the client and monitor for resolution. If pain persists or worsens after curing, further assessment is needed."),
  rpn("REX-PN","Musculoskeletal",2,"A client with gout should be instructed to avoid:",["Fruits and vegetables","Organ meats, shellfish, and alcohol","Whole grains and dairy","Lean chicken and fish"],1,"Gout results from uric acid crystal deposition in joints. Purine-rich foods (organ meats, shellfish, red meat) and alcohol increase uric acid production. Adequate hydration and medications (allopurinol, colchicine) help prevent attacks."),
  rpn("REX-PN","Renal",3,"A client with chronic kidney disease has a phosphorus level of 7.2 mg/dL. The nurse should administer:",["Calcium supplements with meals","Phosphate binders with meals","Potassium supplements","Vitamin D supplements only"],1,"Elevated phosphorus in CKD is managed with phosphate binders (calcium acetate, sevelamer, lanthanum) taken WITH meals to bind dietary phosphorus in the gut and prevent absorption. This helps prevent renal osteodystrophy."),
  rpn("REX-PN","Renal",2,"The nurse teaches a female client about preventing urinary tract infections. Which instruction is correct?",["Wipe from back to front after toileting","Take frequent bubble baths","Urinate before and after sexual intercourse","Limit fluid intake to concentrate the urine"],2,"Urinating after intercourse flushes bacteria from the urethra before they can ascend to the bladder. Wiping front to back, adequate hydration, avoiding irritants, and cotton underwear also help prevent UTIs."),
  rpn("REX-PN","Maternal/Newborn",3,"A client at 26 weeks gestation presents with regular contractions and cervical dilation. The nurse should anticipate administration of:",["Oxytocin to augment labor","Betamethasone to promote fetal lung maturity","Misoprostol for cervical ripening","Magnesium sulfate for seizure prevention only"],1,"Antenatal corticosteroids (betamethasone) are given between 24-34 weeks to accelerate fetal lung surfactant production, reducing the risk of respiratory distress syndrome. Tocolytics may also be given to delay delivery long enough for steroids to take effect."),
  rpn("RPN-CAT","Maternal/Newborn",2,"A newborn has a temperature of 36.0C. The nurse should:",["Document as within normal range","Apply warming measures such as skin-to-skin contact and warming blanket","Apply cool compresses","Bathe the newborn immediately"],1,"Newborn temperature below 36.5C indicates hypothermia. Skin-to-skin contact (kangaroo care) and warming blankets are effective interventions. Newborns lose heat through evaporation, conduction, convection, and radiation. Bathing should be delayed until temperature stabilizes."),
  rpn("REX-PN","Maternal/Newborn",2,"The nurse assesses a 2-day-old newborn and notes a yellowish tinge to the skin. This physiologic jaundice is caused by:",["Liver disease","Normal breakdown of fetal red blood cells","Biliary atresia","Blood type incompatibility"],1,"Physiologic jaundice appearing after 24 hours of life results from the normal breakdown of excess fetal red blood cells and the newborn liver's immature conjugation capacity. It typically resolves within 1-2 weeks. Jaundice before 24 hours is pathologic."),
  rpn("REX-PN","Infection Control",3,"The nurse is caring for a client with varicella (chickenpox). Which isolation precautions are required?",["Contact precautions only","Airborne and contact precautions","Droplet precautions only","Standard precautions only"],1,"Varicella (chickenpox) requires both airborne precautions (negative-pressure room, N95 respirator) because the virus is transmitted via small airborne particles, and contact precautions because the vesicle fluid is also infectious."),
  rpn("REX-PN","Hematological",2,"A client with sickle cell disease should be instructed to:",["Exercise vigorously to stay fit","Maintain adequate hydration to prevent sickling","Limit fluid intake","Avoid routine immunizations"],1,"Dehydration increases blood viscosity and promotes sickling of red blood cells. Maintaining adequate hydration (2-3 L/day) reduces sickling risk. Other preventive measures include avoiding high altitude, extreme temperatures, and infection."),
  rpn("RPN-CAT","Hematological",3,"A client receiving a platelet transfusion has a pre-transfusion count of 8,000/mm3. The nurse should monitor for:",["Fluid overload and transfusion reaction","Immediate rise to normal platelet levels","Hemolytic reaction with hemoglobinuria","No monitoring needed for platelet transfusions"],0,"Platelet transfusions require monitoring for transfusion reactions (fever, chills, urticaria), fluid overload, and therapeutic response. One unit of platelets increases the count by approximately 5,000-10,000/mm3. Severely thrombocytopenic clients need multiple units."),
  rpn("REX-PN","Integumentary",3,"A client with severe burns is at greatest risk for which systemic complication in the first 24 hours?",["Infection","Hypovolemic shock from fluid shift","Renal failure from dehydration","Sepsis"],1,"In the first 24-48 hours after severe burns, massive capillary permeability causes fluid to shift from intravascular to interstitial space, leading to hypovolemic shock. The Parkland formula guides fluid resuscitation: 4 mL x kg x %TBSA burned."),
  rpn("REX-PN","Immunological",2,"A client asks about the difference between active and passive immunity. The nurse explains that vaccination provides:",["Passive immunity with immediate but short-lasting protection","Active immunity through stimulating the body's own immune response","No immune protection","Passive immunity that lasts a lifetime"],1,"Vaccines provide active immunity by exposing the immune system to antigens, stimulating antibody production and memory cell formation. Protection develops over weeks but is long-lasting. Passive immunity (immune globulin) provides immediate but temporary protection."),
  rpn("REX-PN","Reproductive",3,"A client with endometriosis reports severe dysmenorrhea and dyspareunia. The nurse should explain that treatment options include:",["Only surgical intervention","Hormonal therapy to suppress ovulation and surgical options","Antibiotics for infection","Increased physical activity during menstruation"],1,"Endometriosis treatment includes hormonal therapy (OCPs, GnRH agonists, progestins) to suppress ovulation and endometrial growth, NSAIDs for pain, and surgical options (laparoscopy for ablation or excision, hysterectomy for severe cases)."),
  rpn("REX-PN","Emergency",3,"A client presenting with heat stroke has a core temperature of 41C and altered mental status. The nurse should:",["Administer antipyretics immediately","Begin rapid external cooling with ice packs to groin, axillae, and neck","Wait for the temperature to decrease naturally","Administer warm IV fluids"],1,"Heat stroke is a medical emergency requiring immediate aggressive cooling. Ice packs to the groin, axillae, and neck target major blood vessels. Additional methods include evaporative cooling (misting with cool water and fans), cool IV fluids, and ice water immersion."),
  rpn("REX-PN","Oncology",3,"A client receiving radiation therapy to the abdomen reports persistent diarrhea. The nurse should recommend:",["High-fiber diet to slow motility","Low-residue diet and adequate hydration","Increasing dairy product intake","Eating large meals to maintain weight"],1,"Radiation to the abdomen can cause enteritis with diarrhea. A low-residue (low-fiber) diet reduces bowel stimulation. Adequate hydration replaces fluid losses. Antidiarrheal medications may be prescribed. Avoid irritating foods, dairy, and caffeine."),
  rpn("RPN-CAT","Perioperative",2,"The nurse is preparing a client for surgery. Which finding would the nurse report to the surgeon immediately?",["The client ate breakfast 2 hours ago","The client's blood pressure is 126/78","The client's hemoglobin is 14 g/dL","The client reports mild anxiety about surgery"],0,"Eating 2 hours before surgery violates NPO requirements, increasing aspiration risk during anesthesia. The surgeon and anesthesiologist must be notified as the procedure may need to be postponed. All other findings are within normal limits."),
  rpn("REX-PN","Safety",2,"When using a Hoyer (mechanical) lift to transfer a client, the nurse should:",["Use the lift independently without assistance","Ensure proper sling placement and use at least two staff members","Allow the client to hold onto the lift frame during transfer","Move the lift quickly to minimize client anxiety"],1,"Mechanical lifts require proper sling placement and at least two trained staff for safe transfer. The client should not hold onto the lift frame. Move slowly and smoothly, keeping the client's center of gravity low. Inspect equipment before each use."),
  rpn("REX-PN","Geriatrics",2,"The nurse is assessing fall risk in an elderly client. Which validated tool should be used?",["Braden scale","Morse Fall Scale","Glasgow Coma Scale","Norton scale"],1,"The Morse Fall Scale is a validated tool assessing fall risk factors: history of falling, secondary diagnosis, ambulatory aids, IV/heparin lock, gait, and mental status. Scores guide interventions. The Braden and Norton scales assess pressure injury risk."),
  rpn("REX-PN","Community Health",2,"When teaching a community group about fire safety, the nurse should emphasize:",["Installing and maintaining working smoke detectors on every level","Storing flammable materials in the kitchen for convenience","Leaving candles burning when leaving a room","Using extension cords under rugs for neatness"],0,"Working smoke detectors reduce fire death risk by 50%. They should be installed on every level, in every bedroom, and tested monthly. Batteries should be replaced annually. Other safety measures include having a fire escape plan and practicing it regularly."),
  rpn("REX-PN","Wound Care",3,"When applying a negative pressure wound therapy (wound VAC) system, the nurse should:",["Change the dressing daily","Ensure an airtight seal around the wound","Apply the foam directly to exposed blood vessels","Disconnect the system during ambulation"],1,"Negative pressure wound therapy requires an airtight seal for the vacuum to function properly. The foam is cut to fit the wound bed, covered with adhesive drape, and connected to suction. Never apply directly to exposed blood vessels, organs, or nerves."),
  rpn("RPN-CAT","Geriatrics",3,"An elderly client is prescribed a new medication that is highly protein-bound. The nurse considers that in older adults:",["Protein binding is increased, requiring higher doses","Decreased albumin levels may increase free drug levels and toxicity risk","Protein-bound drugs are eliminated faster","There is no change in protein binding with aging"],1,"Aging reduces serum albumin levels, decreasing protein binding capacity. More free (unbound) drug is available in circulation, increasing pharmacological effect and toxicity risk. Dosage adjustments may be necessary for highly protein-bound drugs."),
  rpn("REX-PN","Cardiovascular",3,"A client receiving a thrombolytic agent for acute ischemic stroke should NOT have which procedure performed?",["Blood pressure monitoring","Urinary catheter insertion","Arterial puncture","Oral temperature measurement"],2,"Thrombolytics increase bleeding risk significantly. Arterial punctures, IM injections, invasive procedures, and venipuncture should be avoided or minimized. Use pressure dressings at IV sites and avoid unnecessary needle sticks for 24 hours post-administration."),
  rpn("REX-PN","Respiratory",3,"A client with sleep apnea is prescribed CPAP therapy. The nurse teaches that CPAP works by:",["Delivering high-flow oxygen to the lungs","Providing continuous positive airway pressure to keep airways open","Providing intermittent positive pressure ventilation","Delivering aerosolized medication during sleep"],1,"CPAP delivers a continuous stream of pressurized air through a mask, splinting the upper airway open during sleep and preventing the soft tissue collapse that causes obstructive sleep apnea. It reduces apnea episodes and improves oxygenation during sleep."),
  rpn("REX-PN","Neurological",2,"A client with a headache is prescribed sumatriptan. The nurse instructs the client to:",["Take the medication daily for prevention","Take it at the onset of migraine symptoms","Use it with MAOIs for better effect","Ignore side effects as they are temporary"],1,"Sumatriptan is a serotonin receptor agonist (triptan) taken at migraine onset for acute relief. It should not be taken with MAOIs or ergotamines due to serotonin syndrome risk. Maximum doses per 24 hours should not be exceeded."),
  rpn("RPN-CAT","Endocrine",3,"A client with Hashimoto thyroiditis develops myxedema. Physical assessment would reveal:",["Warm, moist skin and tachycardia","Cool, dry skin, facial puffiness, and periorbital edema","Weight loss and diarrhea","Exophthalmos and lid lag"],1,"Myxedema is severe hypothyroidism characterized by nonpitting edema (mucopolysaccharide deposits), cool dry skin, facial puffiness, periorbital edema, bradycardia, hypothermia, constipation, and mental sluggishness. Myxedema coma is the life-threatening extreme."),
  rpn("REX-PN","Gastrointestinal",3,"A client with a malignant bowel obstruction on palliative care has intractable vomiting. The nurse should prepare for:",["Aggressive IV hydration","Placement of a venting gastrostomy tube for decompression","Surgical resection of the tumor","Administration of laxatives"],1,"In palliative care for malignant obstruction, a venting gastrostomy tube provides continuous decompression and symptom relief without nasogastric tube discomfort. This allows the client to take small amounts of oral fluids for comfort."),
  rpn("REX-PN","Pharmacology",2,"When administering eye drops, the nurse should instill the medication into the:",["Center of the eye directly on the cornea","Lower conjunctival sac","Upper eyelid margin","Inner canthus while the eye is closed"],1,"Eye drops are instilled into the lower conjunctival sac to prevent corneal damage and allow proper distribution. The client should look up, the nurse gently pulls down the lower lid, and drops are placed in the pocket without touching the dropper to the eye."),
  rpn("REX-PN","Mental Health",2,"A client admitted to the psychiatric unit has been prescribed a PRN anxiolytic. Before administering the medication, the nurse should first:",["Administer the medication immediately upon the client's request","Assess the client's current anxiety level and try non-pharmacological interventions","Wait until the client requests it a second time","Check if the client has taken the medication before"],1,"Before administering PRN anxiolytics, the nurse should assess current anxiety level, try non-pharmacological interventions (deep breathing, guided imagery, grounding), and determine if medication is necessary. This promotes therapeutic communication and prevents overreliance on medication."),
  rpn("REX-PN","Pediatrics",3,"A child with Kawasaki disease should be monitored for which cardiac complication?",["Atrial fibrillation","Coronary artery aneurysm","Ventricular hypertrophy","Mitral valve prolapse"],1,"Kawasaki disease causes vasculitis affecting medium-sized arteries, particularly coronary arteries. Coronary artery aneurysms develop in 15-25% of untreated children. Early treatment with IV immunoglobulin and aspirin reduces this risk to about 5%."),
  rpn("RPN-CAT","Pediatrics",2,"The nurse is calculating a pediatric IV fluid maintenance rate using the Holliday-Segar method. For a 10 kg child, the rate is:",["50 mL/hour","approximately 40 mL/hour (1000 mL/24 hours)","100 mL/hour","25 mL/hour"],1,"Holliday-Segar method: 100 mL/kg/day for the first 10 kg. For a 10 kg child: 100 x 10 = 1000 mL/day = approximately 42 mL/hour. This ensures adequate hydration for the child's metabolic needs."),
  rpn("REX-PN","Fundamentals",2,"The nurse documents the client's pain as '8/10, sharp, located in the right lower quadrant, worsening with movement.' This is an example of:",["Objective data only","Subjective data combined with objective assessment","An incomplete pain assessment","A nursing diagnosis"],1,"Pain assessment combines subjective data (client's rating of 8/10) with objective assessment (location, quality, aggravating factors). Comprehensive pain assessment uses PQRST: Provocation, Quality, Region/Radiation, Severity, Timing."),
  rpn("REX-PN","Fundamentals",2,"When applying an elastic bandage to a lower extremity, the nurse should wrap from:",["Proximal to distal","Distal to proximal","The middle outward in both directions","Any direction that is comfortable"],1,"Elastic bandages are applied from distal to proximal to promote venous return and prevent blood pooling in the extremity. Wrapping should be firm but not tight, with even tension, and overlapping each turn by half. Assess circulation after application."),
  rpn("REX-PN","Renal",3,"A client undergoing hemodialysis develops disequilibrium syndrome. Symptoms include:",["Hypertension and bradycardia","Headache, nausea, confusion, and possible seizures","Improved energy and appetite","Decreased BUN levels only"],1,"Dialysis disequilibrium syndrome results from rapid removal of solutes during dialysis, creating an osmotic gradient that draws water into brain cells. Symptoms include headache, nausea, restlessness, confusion, and in severe cases, seizures and coma."),

  // === RN ADDITIONAL (need ~941 more to reach 2500) ===
  rn("NCLEX-RN","Cardiovascular",3,"A client post-CABG has a chest tube output of 250 mL in the first hour. The nurse should:",["Document as expected postoperative drainage","Notify the surgeon as output exceeds expected range","Increase IV fluids to compensate","Clamp the chest tube"],1,"Expected chest tube drainage after CABG is < 200 mL in the first hour, decreasing thereafter. Output > 200 mL/hour for 2+ hours suggests surgical bleeding requiring evaluation and possible surgical re-exploration."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with heart failure has a Swan-Ganz catheter showing a cardiac index of 1.8 L/min/m2. This indicates:",["Normal cardiac function","Adequate cardiac output","Cardiogenic shock requiring inotropic support","Volume overload only"],2,"Normal cardiac index is 2.5-4.0 L/min/m2. A CI of 1.8 indicates severely reduced cardiac output relative to body size, consistent with cardiogenic shock. Inotropic support (dobutamine, milrinone) and vasopressor therapy may be required."),
  rn("NCLEX-RN","Cardiovascular",4,"A client with an IABP (intra-aortic balloon pump) develops sudden loss of augmentation on the arterial waveform. The nurse should:",["Continue monitoring without intervention","Assess for balloon displacement and notify the physician","Increase the balloon inflation timing","Deflate the balloon and remove it independently"],1,"Loss of augmentation suggests balloon displacement, deflation, or mechanical failure. The nurse should assess the catheter position, check the helium supply, evaluate timing, and notify the physician immediately. Never remove the balloon without physician order."),
  rn("NCLEX-RN","Respiratory",4,"A client on mechanical ventilation develops auto-PEEP. The nurse should anticipate:",["Increasing the respiratory rate","Decreasing the respiratory rate and allowing longer expiratory time","Increasing the tidal volume","Disconnecting the ventilator"],1,"Auto-PEEP (intrinsic PEEP) occurs when the client cannot fully exhale before the next breath, trapping air. Decreasing the respiratory rate allows more time for exhalation, reducing air trapping. Other interventions include increasing expiratory flow and treating bronchospasm."),
  rn("NCLEX-RN","Respiratory",3,"A client with a massive hemothorax has a chest tube draining 1500 mL of blood upon insertion. The nurse should:",["Continue to monitor drainage every hour","Prepare for possible autotransfusion and emergent thoracotomy","Clamp the chest tube to prevent further blood loss","Remove the chest tube and apply a pressure dressing"],1,"Massive hemothorax with > 1500 mL initial drainage or > 200 mL/hour for 2-4 hours indicates major vascular injury requiring emergent thoracotomy. Autotransfusion of shed blood may be utilized. The chest tube should never be clamped."),
  rn("NCLEX-RN","Neurological",4,"A client with status epilepticus has not responded to lorazepam. The nurse should anticipate:",["Repeating lorazepam indefinitely","Loading dose of IV fosphenytoin or phenytoin","Administering oral valproic acid","Performing an immediate CT scan"],1,"For benzodiazepine-refractory status epilepticus, second-line treatment is IV fosphenytoin or phenytoin loading dose. Fosphenytoin is preferred as it can be infused faster with less risk of cardiovascular complications. If seizures continue, general anesthesia may be required."),
  rn("NCLEX-RN","Neurological",3,"A client with myasthenia gravis is being evaluated for myasthenic vs. cholinergic crisis. The edrophonium (Tensilon) test is performed. Improvement of symptoms indicates:",["Cholinergic crisis","Myasthenic crisis (underdosed anticholinesterase)","Both crises resolved","Neither crisis present"],1,"The Tensilon test differentiates myasthenic from cholinergic crisis. If symptoms improve (increased strength) after edrophonium, the client has myasthenic crisis (needs more anticholinesterase). Worsening symptoms indicate cholinergic crisis (overmedicated)."),
  rn("NCLEX-RN","Endocrine",3,"A client with Addison disease is taught about sick day rules. The nurse instructs:",["Decrease corticosteroid dose during illness","Double or triple the corticosteroid dose during physical stress","Stop corticosteroids and take NSAIDs instead","Maintain the same dose regardless of illness"],1,"During illness, surgery, or significant stress, clients with Addison disease must increase their corticosteroid dose (typically double or triple) because their adrenal glands cannot produce the additional cortisol needed during stress. Failure to do so can precipitate adrenal crisis."),
  rn("NCLEX-RN","Endocrine",3,"A client with a prolactinoma presents with galactorrhea and amenorrhea. First-line treatment is:",["Surgical resection","Dopamine agonist therapy (cabergoline or bromocriptine)","Radiation therapy","Observation only"],1,"Dopamine agonists are first-line for prolactinomas regardless of size. Dopamine inhibits prolactin secretion. Cabergoline is preferred over bromocriptine due to better efficacy and tolerability. Surgery is reserved for medication-resistant tumors."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with alcoholic cirrhosis develops spontaneous bacterial peritonitis. The nurse should anticipate:",["Oral antibiotics only","IV ceftriaxone or cefotaxime and albumin infusion","Paracentesis without antibiotics","Surgical drainage of the ascites"],1,"SBP in cirrhosis is treated with IV third-generation cephalosporin (ceftriaxone or cefotaxime) and albumin infusion to prevent hepatorenal syndrome. Diagnostic paracentesis showing neutrophil count > 250/mm3 confirms SBP."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute upper GI bleeding has a Blatchford score of 12. This indicates:",["Low risk, can be managed as outpatient","High risk, requires urgent endoscopy and resuscitation","Moderate risk, can wait for elective endoscopy","Score has no clinical significance"],1,"The Blatchford score assesses the need for clinical intervention in upper GI bleeding. Scores > 6 indicate high risk requiring urgent endoscopy, IV PPI infusion, hemodynamic resuscitation, and possible blood transfusion. Score of 0 may be suitable for outpatient management."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving amiodarone should have which baseline and ongoing tests monitored?",["CBC and urinalysis","Thyroid function, liver function, and pulmonary function tests","Serum glucose and hemoglobin A1c","Lipid panel and coagulation studies"],1,"Amiodarone has multiple serious adverse effects requiring monitoring: pulmonary fibrosis (PFTs, chest X-ray), thyrotoxicosis or hypothyroidism (TFTs), hepatotoxicity (LFTs), corneal microdeposits (ophthalmologic exam), and photosensitivity."),
  rn("NCLEX-RN","Pharmacology",4,"A client on a dopamine drip at 15 mcg/kg/min is exhibiting which predominant pharmacological effect?",["Renal vasodilation (dopaminergic effect)","Beta-1 cardiac stimulation","Alpha-1 peripheral vasoconstriction","No significant effect at this dose"],2,"Dopamine dose effects: 1-3 mcg/kg/min = dopaminergic (renal vasodilation), 3-10 mcg/kg/min = beta-1 (increased cardiac output), > 10 mcg/kg/min = alpha-1 (vasoconstriction, increased SVR). At 15 mcg/kg/min, alpha vasoconstriction predominates."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving IV potassium develops peaked T waves on the cardiac monitor. The nurse should:",["Continue the infusion as this is expected","Stop the infusion and obtain a stat potassium level","Increase the infusion rate","Administer another dose of potassium"],1,"Peaked T waves indicate hyperkalemia, a potentially fatal complication of IV potassium administration. The infusion must be stopped immediately. Stat potassium level, 12-lead ECG, and calcium gluconate should be obtained. Hyperkalemia can cause lethal arrhythmias."),
  rn("NCLEX-RN","Mental Health",3,"A client with acute mania is displaying flight of ideas, grandiosity, and pressured speech. The priority nursing intervention is:",["Engaging the client in group therapy","Providing a calm, low-stimulation environment with safety measures","Confronting the grandiose beliefs with reality","Encouraging the client to express all their ideas"],1,"During acute mania, the priority is safety and reducing stimulation. A private, quiet room with minimal stimulation helps decrease agitation. Set firm, consistent limits. Short, clear communications are most effective. Group therapy is inappropriate during acute episodes."),
  rn("NCLEX-RN","Mental Health",3,"A nurse is working with a client who dissociates during therapy. The most appropriate intervention is:",["End the session immediately","Use grounding techniques to bring the client to the present","Continue the session without addressing the dissociation","Administer an anxiolytic medication"],1,"Grounding techniques (sensory awareness: '5 things you see, 4 you hear,' deep breathing, ice in hand) help orient the client to the present during dissociative episodes. The nurse should remain calm, speak clearly, and help the client reconnect with the environment."),
  rn("NCLEX-RN","Pediatrics",3,"A neonate has a positive Ortolani test. This finding indicates:",["Normal hip joint mobility","Developmental dysplasia of the hip","Congenital knee dislocation","Fracture of the femur"],1,"A positive Ortolani test (a 'clunk' felt when abducting the hip with anterior pressure on the greater trochanter) indicates a dislocated hip being reduced back into the acetabulum. This confirms developmental dysplasia of the hip requiring a Pavlik harness."),
  rn("NCLEX-RN","Pediatrics",3,"A child with hemolytic uremic syndrome (HUS) following an E. coli O157:H7 infection should be monitored for:",["Hepatic failure","Thrombotic thrombocytopenic purpura","Acute kidney injury, thrombocytopenia, and hemolytic anemia","Meningitis"],2,"HUS classically presents with the triad of microangiopathic hemolytic anemia, thrombocytopenia, and acute kidney injury. It is the most common cause of AKI in young children. Management is supportive: fluid management, dialysis if needed, and blood transfusions."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A pregnant client at 28 weeks has a positive glucose challenge test (GCT) with a value of 155 mg/dL. The next step is:",["Diagnosis of gestational diabetes","3-hour oral glucose tolerance test (OGTT)","Immediate insulin therapy","Repeat the GCT in one month"],1,"A GCT >= 140 mg/dL (or >= 130 in some centers) is a positive screening result but not diagnostic. The 3-hour OGTT with 100g glucose load is the diagnostic test. Two or more abnormal values on the OGTT confirms gestational diabetes."),
  rn("NCLEX-RN","Maternal/Newborn",4,"A client with complete placental abruption presents with a rigid, board-like abdomen and dark vaginal bleeding. The nurse should:",["Prepare for vaginal delivery","Prepare for emergency cesarean delivery","Administer tocolytics to stop contractions","Perform a digital cervical exam"],1,"Complete placental abruption with a rigid abdomen is a obstetric emergency threatening both maternal and fetal life. Emergency cesarean delivery is indicated. Monitor for DIC. Digital exam is not the priority; focus is on rapid delivery and hemorrhage management."),
  rn("NCLEX-RN","Renal",4,"A client with acute kidney injury has a BUN/creatinine ratio of 35:1. This pattern suggests:",["Intrinsic renal failure","Prerenal azotemia (decreased renal perfusion)","Postrenal obstruction","Chronic kidney disease"],1,"BUN/creatinine ratio > 20:1 suggests prerenal azotemia from decreased renal perfusion (hypovolemia, heart failure, renal artery stenosis). The kidneys retain urea preferentially over creatinine. Intrinsic renal failure typically has a ratio of 10-15:1."),
  rn("NCLEX-RN","Hematological",3,"A client with immune thrombocytopenic purpura (ITP) has not responded to corticosteroid therapy. The nurse should anticipate:",["Platelet transfusion as definitive treatment","IVIG or anti-D immunoglobulin therapy","Immediate splenectomy","Chemotherapy"],1,"For ITP refractory to corticosteroids, IVIG provides rapid platelet increase by blocking Fc receptors on macrophages. Anti-D immunoglobulin works similarly in Rh-positive clients. Splenectomy is considered for chronic ITP unresponsive to medical therapy."),
  rn("NCLEX-RN","Immunological",4,"A client develops graft-versus-host disease after bone marrow transplant. The nurse assesses for the classic triad of:",["Pneumonia, hepatitis, and nephritis","Skin rash, diarrhea, and liver dysfunction","Fever, pancytopenia, and bleeding","Joint pain, proteinuria, and hypertension"],1,"GVHD occurs when donor immune cells attack the recipient's tissues. The classic triad involves skin (maculopapular rash), GI (diarrhea, abdominal pain), and liver (elevated bilirubin, transaminases). It is treated with immunosuppressive therapy."),
  rn("NCLEX-RN","Integumentary",3,"A client with a stage 3 pressure injury has a wound bed with 80% red granulation tissue and 20% yellow slough. The nurse should:",["Apply a dry gauze dressing","Use autolytic debridement with a moisture-retentive dressing","Pack the wound tightly with gauze","Apply povidone-iodine to all wound tissue"],1,"Wounds with mixed tissue types benefit from autolytic debridement using moisture-retentive dressings (hydrogel, hydrocolloid) that soften slough while protecting granulation tissue. Mechanical debridement may damage healthy tissue. Povidone-iodine is cytotoxic to new tissue."),
  rn("RN-CAT","Cardiovascular",3,"A client in cardiogenic shock has the following hemodynamic values: CI 1.5, SVR 2000, PCWP 24. Which inotrope is most appropriate?",["Norepinephrine","Dobutamine","Phenylephrine","Vasopressin"],1,"Dobutamine is the inotrope of choice for cardiogenic shock with high PCWP and SVR. It increases cardiac contractility and output while reducing afterload through mild vasodilation. Norepinephrine increases SVR further. Phenylephrine is a pure vasoconstrictor."),
  rn("RN-CAT","Respiratory",4,"A ventilated client has a plateau pressure of 35 cmH2O and peak pressure of 45 cmH2O. This suggests:",["Normal ventilator mechanics","Both increased airway resistance and decreased compliance","Ventilator malfunction only","Endotracheal tube cuff leak"],1,"High PIP suggests airway resistance issues (secretions, bronchospasm, kinked tube). High plateau pressure indicates decreased lung compliance (pulmonary edema, ARDS, pneumothorax). Both being elevated suggests combined problems requiring targeted interventions."),
  rn("RN-CAT","Neurological",4,"A client with bacterial meningitis is being treated with dexamethasone before antibiotics. The nurse understands this is to:",["Reduce fever for patient comfort","Reduce cerebral edema and decrease inflammatory response to bacterial lysis","Treat the bacterial infection directly","Prevent seizures"],1,"Dexamethasone given before or with the first dose of antibiotics reduces the inflammatory cascade triggered by bacterial cell wall lysis. This decreases cerebral edema, intracranial pressure, and improves outcomes, particularly in pneumococcal meningitis."),
  rn("RN-CAT","Endocrine",3,"A client with a pituitary macroadenoma develops bitemporal hemianopsia. This occurs because the tumor compresses:",["The frontal lobe","The optic chiasm","The temporal lobe","The occipital cortex"],1,"The pituitary gland sits immediately below the optic chiasm. Upward growth of a pituitary adenoma compresses the crossing fibers at the chiasm, causing bitemporal hemianopsia (loss of peripheral vision in both temporal fields)."),
  rn("RN-CAT","Gastrointestinal",3,"A client with cirrhosis and portal hypertension is started on propranolol. This is prescribed to:",["Lower blood pressure systemically","Reduce portal pressure and prevent variceal bleeding","Treat underlying liver disease","Manage hepatic encephalopathy"],1,"Non-selective beta-blockers (propranolol, nadolol) reduce portal pressure by decreasing cardiac output (beta-1) and causing splanchnic vasoconstriction (beta-2). Primary prophylaxis reduces first variceal bleed risk by 40-50%."),
  rn("RN-CAT","Pharmacology",4,"A client is receiving a continuous insulin drip in the ICU. The nurse should:",["Administer the insulin through any available IV line","Use a dedicated IV line with an infusion pump and monitor glucose hourly","Mix insulin with the maintenance IV fluids","Bolus insulin every 4 hours based on fingerstick results"],1,"Continuous insulin infusion requires a dedicated line, infusion pump for precise delivery, and hourly glucose monitoring. Mixing with other fluids alters concentration. Regular insulin is the only type used for IV continuous infusion. Potassium levels must also be monitored."),
  rn("RN-CAT","Mental Health",3,"A client with anorexia nervosa is admitted with a BMI of 14. The nurse's priority assessment is:",["Body image disturbance","Cardiac arrhythmias and electrolyte imbalances","Family dynamics","Self-esteem level"],1,"Severe malnutrition (BMI < 15) causes life-threatening cardiac arrhythmias from electrolyte imbalances (hypokalemia, hypomagnesemia, hypophosphatemia). QT prolongation and refeeding syndrome risk are the primary physiological concerns requiring immediate medical stabilization."),
  rn("RN-CAT","Pediatrics",3,"A premature infant born at 28 weeks develops necrotizing enterocolitis. The nurse assesses for:",["Excessive weight gain","Abdominal distension, bloody stools, and feeding intolerance","Projectile vomiting only","Constipation and hard stools"],1,"NEC presents with abdominal distension, feeding intolerance, bloody or guaiac-positive stools, and pneumatosis intestinalis on X-ray. Management includes NPO status, NG decompression, IV antibiotics, and possible surgical intervention for perforation."),
  rn("RN-CAT","Maternal/Newborn",4,"A client in the second stage of labor develops an umbilical cord prolapse. The nurse should:",["Push the cord back into the vagina","Apply upward pressure on the presenting part and prepare for emergency C-section","Place the client in lithotomy position","Increase oxytocin to speed delivery"],1,"Umbilical cord prolapse is a medical emergency. The nurse applies upward digital pressure on the presenting part to relieve cord compression, positions the client in Trendelenburg or knee-chest position, and prepares for immediate cesarean delivery. Never push the cord back in."),
  rn("RN-CAT","Renal",3,"A client on CRRT (continuous renal replacement therapy) has the filter clotting frequently. The nurse should assess for:",["Adequate anticoagulation of the circuit","Excessive fluid removal rate","High blood urea nitrogen levels","Excessive dietary protein intake"],0,"Frequent filter clotting in CRRT indicates inadequate anticoagulation of the extracorporeal circuit. Regional citrate anticoagulation or systemic heparin may be adjusted. Other causes include slow blood flow rates, high hematocrit, or kinking of the circuit."),
  rn("RN-CAT","Critical Care",4,"A client in the ICU develops torsades de pointes. The nurse should immediately prepare:",["Amiodarone IV push","IV magnesium sulfate and overdrive pacing","Lidocaine drip","Adenosine rapid IV push"],1,"Torsades de pointes (polymorphic ventricular tachycardia with QT prolongation) is treated with IV magnesium sulfate 1-2g. Overdrive pacing or isoproterenol may be needed if magnesium is ineffective. Standard antiarrhythmics (amiodarone, procainamide) can worsen torsades."),
  rn("RN-CAT","Critical Care",4,"A client develops abdominal compartment syndrome with a bladder pressure of 28 mmHg. The nurse should anticipate:",["Conservative management with monitoring","Surgical decompressive laparotomy","Nasogastric decompression only","Paracentesis"],1,"Abdominal compartment syndrome (bladder pressure > 20 mmHg with organ dysfunction) requires decompressive laparotomy to relieve pressure on abdominal organs and improve perfusion. Sustained elevated intra-abdominal pressure causes renal failure, respiratory compromise, and cardiovascular collapse."),
  rn("NCLEX-RN","Cardiovascular",3,"A client post-MI on day 2 develops a new holosystolic murmur at the left sternal border. The nurse suspects:",["Normal healing process","Ventricular septal rupture or papillary muscle rupture","Pericarditis","Aortic stenosis"],1,"New holosystolic murmur 2-5 days post-MI suggests mechanical complications: ventricular septal rupture (murmur at left sternal border) or papillary muscle rupture causing acute mitral regurgitation. Both are surgical emergencies with high mortality."),
  rn("NCLEX-RN","Respiratory",3,"A client with COPD and cor pulmonale develops right-sided heart failure. The nurse should anticipate treatment with:",["High-flow oxygen and aggressive diuresis","Low-flow oxygen, diuretics, and sodium restriction","Positive inotropes and fluid boluses","Anticoagulation therapy only"],1,"Cor pulmonale (right heart failure from pulmonary disease) is managed with treating the underlying lung disease (low-flow O2 for COPD), diuretics for fluid overload, sodium restriction, and possibly pulmonary vasodilators."),
  rn("NCLEX-RN","Neurological",3,"A client with a traumatic brain injury has an ICP monitor reading 25 mmHg. Nursing interventions include:",["Lowering the head of the bed flat","Elevating HOB 30 degrees, keeping head midline, and avoiding clustering care","Encouraging coughing and deep breathing frequently","Administering hypotonic IV fluids"],1,"ICP management includes elevating HOB 30 degrees (promotes venous drainage), keeping head midline (prevents jugular vein compression), spacing nursing activities (prevents ICP spikes from clustering), maintaining normothermia, and administering osmotic diuretics as ordered."),
  rn("NCLEX-RN","Endocrine",4,"A client with pheochromocytoma is scheduled for surgery. Pre-operative management MUST include:",["Beta-blocker initiation first","Alpha-adrenergic blockade for 10-14 days before surgery","Immediate surgical resection without medical preparation","Calcium channel blocker therapy only"],1,"Pre-operative alpha-blockade (phenoxybenzamine or doxazosin) for 10-14 days controls hypertension and expands contracted blood volume. Beta-blockers are added AFTER alpha-blockade to control tachycardia. Starting beta-blockers first causes unopposed alpha stimulation and hypertensive crisis."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute cholangitis presents with Charcot triad. The nurse should recognize this as:",["Fever, RUQ pain, and jaundice","Fever, jaundice, and diarrhea","Nausea, vomiting, and RUQ pain","Jaundice, weight loss, and pruritus"],0,"Charcot triad (fever with chills, jaundice, RUQ pain) indicates acute cholangitis from biliary obstruction with infection. Reynolds pentad adds hypotension and confusion, indicating septic cholangitis requiring emergent biliary drainage."),
  rn("NCLEX-RN","Pharmacology",3,"A client on continuous heparin infusion should have which test monitored?",["Prothrombin time (PT)","Activated partial thromboplastin time (aPTT)","International normalized ratio (INR)","Fibrinogen level"],1,"Heparin effectiveness is monitored by aPTT (therapeutic goal: 1.5-2.5 times control). PT/INR monitors warfarin effectiveness. aPTT should be checked 6 hours after dose changes and daily when stable. Anti-Xa levels may also be used."),
  rn("NCLEX-RN","Mental Health",4,"A client with serotonin syndrome develops hyperthermia, clonus, and agitation after combining an SSRI with tramadol. The nurse should:",["Administer another dose of the SSRI","Discontinue both medications and initiate cooling measures","Administer a benzodiazepine for agitation only","Continue both medications and monitor"],1,"Serotonin syndrome is a potentially fatal condition from excessive serotonergic activity. Treatment includes discontinuing all serotonergic agents, aggressive cooling, benzodiazepines for agitation/rigidity, and cyproheptadine (serotonin antagonist) for moderate to severe cases."),
  rn("NCLEX-RN","Pediatrics",3,"A child with Wilms tumor should have a sign posted at the bedside stating:",["No rectal temperatures","Do not palpate the abdomen","Fall precautions","Contact isolation"],1,"Palpation of a Wilms tumor can cause tumor rupture and seeding of cancer cells into the abdomen. A sign should be posted prominently. Pre-operative nursing care avoids abdominal palpation, and careful handling during bathing and positioning is essential."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client receiving magnesium sulfate for preeclampsia has absent deep tendon reflexes. The nurse should:",["Continue the infusion and monitor","Stop the infusion and administer calcium gluconate","Increase the infusion rate","Check the client's blood pressure"],1,"Absent DTRs indicate magnesium toxicity (therapeutic range 4-7 mEq/L). The infusion must be stopped. Calcium gluconate (the antidote) should be administered if symptoms progress. Assessment order for toxicity: decreased DTRs, respiratory depression, cardiac arrest."),
  rn("NCLEX-RN","Renal",3,"A client with nephrolithiasis has a stone composed of calcium oxalate. Dietary education should include:",["Increasing dairy product intake","Limiting oxalate-rich foods such as spinach, chocolate, and tea","Increasing purine-rich foods","Acidifying the urine with cranberry juice"],1,"Calcium oxalate stones are the most common type. Dietary management includes limiting oxalate-rich foods (spinach, rhubarb, chocolate, nuts, tea), maintaining adequate calcium intake (paradoxically reduces oxalate absorption), and increasing fluid intake to > 2.5 L/day."),
  rn("NCLEX-RN","Infection Control",3,"A healthcare worker is exposed to blood and body fluids. After washing the affected area, the MOST important next step is:",["Complete an incident report","Report to occupational health immediately for risk assessment","Wait to see if symptoms develop","Apply hydrogen peroxide to the area"],1,"After washing the exposure site, immediate reporting to occupational health enables rapid risk assessment, baseline testing (HIV, HBV, HCV), and timely initiation of post-exposure prophylaxis (PEP) if indicated. PEP is most effective within 1-2 hours of exposure."),
  rn("RN-CAT","Cardiovascular",3,"A client with Takotsubo cardiomyopathy (stress cardiomyopathy) presents after emotional stress with chest pain mimicking MI. The nurse should expect:",["Coronary artery occlusion on catheterization","Apical ballooning of the left ventricle with clean coronary arteries","Valvular disease","Pericardial effusion"],1,"Takotsubo (broken heart syndrome) shows transient apical ballooning with wall motion abnormalities mimicking MI, but coronary arteries are normal on catheterization. It is triggered by emotional or physical stress and typically resolves within weeks."),
  rn("RN-CAT","Respiratory",3,"A client with severe community-acquired pneumonia has a CURB-65 score of 4. The nurse should anticipate:",["Outpatient management with oral antibiotics","ICU admission with IV antibiotics and close monitoring","No antibiotic treatment needed","Supportive care only"],1,"CURB-65 scores >= 3 indicate severe pneumonia with high mortality requiring ICU admission. Components: Confusion, Uremia (BUN > 19), Respiratory rate > 30, Blood pressure (SBP < 90 or DBP < 60), age >= 65. Score 4-5 has 30-day mortality of 27-57%."),
  rn("RN-CAT","Neurological",3,"A client with a C6 spinal cord injury will have preserved function of which movement?",["Finger flexion and grip","Wrist extension (dorsiflexion)","Triceps extension","Hip flexion"],1,"C6 controls wrist extension (radial wrist extensors). This allows tenodesis grip (passive finger flexion when the wrist extends). C7 controls triceps (elbow extension), C8 controls finger flexion, and L2 controls hip flexion."),
  rn("RN-CAT","Pharmacology",3,"A client is started on amiodarone. The nurse should counsel about which long-term precaution?",["Avoid grapefruit juice only","Use sunscreen and protective clothing due to photosensitivity","Take the medication with antacids","Avoid high-potassium foods"],1,"Amiodarone causes photosensitivity and can cause a blue-gray skin discoloration with prolonged use. Patients should use SPF 50+ sunscreen and protective clothing. This is separate from the other serious monitoring requirements (thyroid, pulmonary, liver, eye)."),
  rn("RN-CAT","Mental Health",3,"A nurse working night shift observes a client with schizophrenia talking to an empty corner of the room. The most therapeutic response is:",["Tell the client no one is there and to go back to bed","Ask the client what they are experiencing","Administer a PRN antipsychotic immediately","Document the behavior without interacting"],1,"Asking what the client is experiencing demonstrates a client-centered approach. It allows assessment of the content and dangerousness of the hallucination while maintaining therapeutic communication. The nurse should not argue about reality or ignore the client."),
  rn("RN-CAT","Pediatrics",3,"A child with acute epiglottitis should be managed with which priority intervention?",["Throat culture to identify the organism","Airway management with intubation equipment at bedside","Immediate antibiotic administration without airway assessment","Racemic epinephrine nebulization"],1,"Epiglottitis (now rare due to Hib vaccine) requires immediate airway management. Equipment for intubation and tracheostomy should be at bedside. Keep the child calm in an upright position. Never examine the throat as it can cause complete airway obstruction."),
  rn("RN-CAT","Infection Control",3,"A client with Clostridioides difficile infection has recurrent episodes despite vancomycin treatment. The nurse should anticipate:",["Higher dose vancomycin","Fecal microbiota transplant consideration","Metronidazole monotherapy","Probiotics alone"],0,"Recurrent C. diff infection unresponsive to standard antibiotic therapy may benefit from fecal microbiota transplant (FMT), which has > 90% cure rate for recurrent CDI. FMT restores normal gut flora diversity that competes with C. diff."),
  rn("RN-CAT","Maternal/Newborn",3,"A postpartum client had a forceps-assisted delivery. The nurse should monitor the neonate for:",["Hyperthermia","Facial bruising, cephalohematoma, and facial nerve palsy","Shoulder dystocia","Meconium aspiration"],1,"Forceps delivery can cause neonatal facial bruising, cephalohematoma (subperiosteal bleeding), and facial nerve (CN VII) palsy from forceps pressure. Maternal complications include vaginal/cervical lacerations. Most neonatal injuries are temporary and resolve spontaneously."),

  // === NP ADDITIONAL (need ~320 more to reach 2000) ===
  np("AANP","Cardiovascular",3,"A 60-year-old with stable angina has an exercise tolerance test showing 2mm ST depression. The NP should recommend:",["Medical management and risk factor modification","Immediate cardiac catheterization for all patients","Bed rest and activity restriction","Repeat stress test in 3 months"],0,"Stable angina with moderate ischemia on stress testing may be initially managed medically with anti-anginal medications (beta-blocker, nitrate, CCB), antiplatelet therapy, and aggressive risk factor modification. Catheterization is indicated for refractory symptoms or high-risk features."),
  np("AANP","Cardiovascular",3,"A patient on ticagrelor reports dyspnea without pulmonary findings. The NP should:",["Discontinue ticagrelor immediately","Reassure the patient this is a known side effect of ticagrelor","Obtain a CT pulmonary angiogram","Start inhaled bronchodilators"],1,"Dyspnea is a known side effect of ticagrelor, occurring in approximately 14% of patients. It is usually benign, often self-limiting, and does not reflect bronchospasm or pulmonary disease. If severe or persistent, switching to clopidogrel may be considered."),
  np("AANP","Cardiovascular",3,"A 45-year-old male with a 10-year ASCVD risk of 8% and LDL of 160 mg/dL should be prescribed:",["No medication, lifestyle changes only","Moderate-intensity statin therapy","High-intensity statin therapy","PCSK9 inhibitor as first-line"],1,"Per ACC/AHA guidelines, patients aged 40-75 with LDL >= 70 and 10-year ASCVD risk 7.5-20% should receive moderate-intensity statin (atorvastatin 10-20mg or rosuvastatin 5-10mg). Risk enhancers may justify high-intensity therapy."),
  np("AANP","Respiratory",3,"A patient with persistent asthma on Step 2 therapy (low-dose ICS) still has symptoms 3-4 days per week. The NP should:",["Double the ICS dose","Step up to low-dose ICS + LABA combination","Add a leukotriene receptor antagonist as monotherapy","Prescribe a short-acting anticholinergic"],1,"Inadequate control on Step 2 warrants Step 3: low-dose ICS + LABA combination (e.g., fluticasone/salmeterol). Adding a LABA to ICS is more effective than doubling the ICS dose. LABA monotherapy is never used in asthma."),
  np("AANP","Respiratory",3,"A COPD patient on LAMA monotherapy has 2 exacerbations in the past year. Per GOLD guidelines, the NP should:",["Continue current therapy","Step up to LAMA + LABA combination","Add an ICS to the current LAMA","Switch to ICS monotherapy"],1,"COPD patients with persistent exacerbations on LAMA monotherapy should be escalated to LAMA + LABA. If still having exacerbations AND eosinophils >= 300, consider adding ICS. The LAMA + LABA + ICS triple therapy is for the most severe cases."),
  np("NP-CAT","Respiratory",3,"A patient presents with chronic cough for 8 weeks. The most common causes in order are:",["Asthma, GERD, lung cancer","Upper airway cough syndrome (post-nasal drip), asthma, GERD","Pneumonia, TB, bronchiectasis","ACE inhibitor, heart failure, lung cancer"],1,"In non-smoking adults with normal chest X-ray, the most common causes of chronic cough are upper airway cough syndrome (34%), asthma (25%), and GERD (20%). ACE inhibitor-induced cough should be ruled out first if applicable."),
  np("AANP","Endocrine",3,"A patient with T2DM has an HbA1c of 10.5% at diagnosis. The NP should consider:",["Metformin monotherapy","Combination therapy or insulin initiation","Lifestyle modifications alone for 6 months","Sulfonylurea monotherapy"],1,"HbA1c >= 10% at diagnosis suggests significant hyperglycemia that may benefit from initial combination therapy (metformin + another agent) or insulin to achieve rapid glycemic control. Monotherapy alone is unlikely to achieve adequate reduction."),
  np("AANP","Endocrine",3,"A postmenopausal woman has a T-score of -1.8. According to WHO criteria, this is classified as:",["Normal bone density","Osteopenia","Osteoporosis","Severe osteoporosis"],1,"WHO classification: T-score >= -1.0 is normal, -1.0 to -2.5 is osteopenia (low bone mass), <= -2.5 is osteoporosis, <= -2.5 with fracture is severe osteoporosis. A T-score of -1.8 is osteopenia. FRAX tool guides treatment decisions."),
  np("NP-CAT","Endocrine",3,"A patient with subclinical hypothyroidism (TSH 8.5, normal free T4) asks about treatment. The NP should:",["Start levothyroxine in all cases","Consider treatment based on symptoms, TPO antibodies, and TSH level","Start liothyronine (T3) therapy","Recommend radioactive iodine ablation"],1,"Subclinical hypothyroidism management is individualized. Treatment is generally recommended for TSH > 10, or TSH 5-10 with symptoms, positive TPO antibodies (predicts progression), or pregnancy/planning pregnancy. Monitor without treatment for asymptomatic mild elevation."),
  np("AANP","Gastrointestinal",3,"A patient with chronic hepatitis C genotype 1 should be treated with:",["Interferon-based therapy","Direct-acting antiviral combination (e.g., sofosbuvir/velpatasvir)","Ribavirin monotherapy","Liver transplant evaluation first"],1,"DAA combinations achieve > 95% SVR (cure) for HCV genotype 1. Sofosbuvir/velpatasvir (Epclusa) is pangenotypic, treating all genotypes. Treatment is typically 12 weeks. Interferon-based regimens are no longer first-line due to inferior efficacy and side effects."),
  np("AANP","Gastrointestinal",2,"A patient presents with dyspepsia and negative H. pylori testing. Initial management should include:",["Immediate endoscopy","4-8 week trial of PPI therapy","Barium swallow study","Surgical referral"],1,"For dyspepsia without alarm features (weight loss, dysphagia, GI bleeding, anemia, age > 60 with new symptoms) and negative H. pylori, empiric PPI therapy for 4-8 weeks is appropriate. Endoscopy is indicated if symptoms persist or alarm features are present."),
  np("NP-CAT","Gastrointestinal",3,"A patient with chronic constipation has tried fiber, hydration, and osmotic laxatives without improvement. The NP should consider:",["Long-term stimulant laxative use only","Anorectal manometry to evaluate for dyssynergic defecation","Colonoscopy as next step","CT scan of the abdomen"],1,"Refractory chronic constipation warrants evaluation for underlying motility disorders. Anorectal manometry evaluates for dyssynergic defecation (paradoxical contraction of the pelvic floor muscles), which responds to biofeedback therapy rather than additional laxatives."),
  np("AANP","Neurological",3,"A patient with a new seizure diagnosis has normal MRI and EEG. Starting medication after a single unprovoked seizure is:",["Always indicated","Based on individual risk factors for recurrence","Never indicated after only one seizure","Dependent on the type of seizure only"],1,"After a single unprovoked seizure, treatment decision depends on recurrence risk factors: abnormal EEG, brain lesion on MRI, nocturnal seizure, Todd paralysis, or family history. Without risk factors, the 2-year recurrence risk is ~30%, and observation may be appropriate."),
  np("NP-CAT","Neurological",3,"A patient with new-onset headache and papilledema should have which test performed urgently?",["Lumbar puncture immediately","CT or MRI of the brain before lumbar puncture","Carotid ultrasound","EEG"],1,"Papilledema suggests elevated intracranial pressure. Brain imaging (CT or MRI) must be performed BEFORE lumbar puncture to rule out mass lesion. LP with mass effect can cause fatal brain herniation. If imaging is normal, LP can then be performed to measure opening pressure."),
  np("AANP","Pharmacology",3,"A patient on methotrexate for rheumatoid arthritis should receive supplemental:",["Vitamin B12","Folic acid 1mg daily","Iron","Vitamin D"],1,"Methotrexate is a folate antagonist. Supplemental folic acid (1mg daily) reduces side effects including stomatitis, nausea, hepatotoxicity, and pancytopenia without decreasing methotrexate efficacy. CBC, liver, and renal function should be monitored regularly."),
  np("AANP","Pharmacology",3,"A patient starting an SSRI should be counseled that the most common initial side effects include:",["Weight gain and sedation","Nausea, headache, and sexual dysfunction","Hypertension and tachycardia","Liver dysfunction and jaundice"],1,"Common SSRI side effects include GI symptoms (nausea, diarrhea), headache, insomnia or somnolence, sexual dysfunction (delayed orgasm, decreased libido), and initial anxiety or agitation. Most GI side effects improve after 1-2 weeks. Sexual dysfunction may persist."),
  np("NP-CAT","Pharmacology",3,"When prescribing metformin, the NP should check which laboratory test at baseline and periodically?",["Liver function tests only","Renal function (eGFR)","Thyroid function tests","Coagulation studies"],1,"Metformin is contraindicated when eGFR < 30 mL/min and dose reduction is recommended for eGFR 30-45. Renal function should be checked at baseline and at least annually. Metformin-associated lactic acidosis risk increases with renal impairment."),
  np("AANP","Mental Health",3,"A patient with MDD has not responded to adequate trial of sertraline. The NP's next step should be:",["Add a benzodiazepine","Switch to another SSRI or SNRI, or augment with bupropion","Increase sertraline indefinitely","Discontinue all medications"],1,"For SSRI non-response after adequate trial (6-8 weeks at therapeutic dose), evidence-based options include switching to another SSRI/SNRI, augmenting with bupropion (different mechanism), or augmenting with atypical antipsychotic (aripiprazole). Step approach guides escalation."),
  np("NP-CAT","Mental Health",3,"A 70-year-old presents with cognitive decline, apathy, and psychomotor retardation. The NP should first rule out:",["Alzheimer disease","Depression (pseudodementia)","Lewy body dementia","Frontotemporal dementia"],1,"Pseudodementia (depression mimicking dementia) is an important differential in elderly patients. Unlike true dementia, depressed patients often report and emphasize cognitive difficulties, have rapid onset, and may improve with antidepressant treatment. PHQ-9 screening is essential."),
  np("AANP","Dermatology",3,"A patient presents with well-demarcated, silvery-white scaly plaques on the elbows and knees. The NP diagnoses:",["Eczema","Psoriasis","Contact dermatitis","Tinea corporis"],1,"Psoriasis presents with well-demarcated, erythematous plaques with silvery-white scales, commonly on extensor surfaces (elbows, knees), scalp, and lower back. Auspitz sign (pinpoint bleeding when scale is removed) is characteristic."),
  np("AANP","Dermatology",2,"A patient with acne vulgaris has moderate inflammatory acne with papules and pustules. First-line treatment is:",["Isotretinoin","Topical retinoid plus topical benzoyl peroxide","Oral antibiotics alone","Chemical peel"],1,"Moderate inflammatory acne is treated with combination topical therapy: retinoid (adapalene, tretinoin) plus benzoyl peroxide (reduces P. acnes and prevents resistance). Oral antibiotics are added for more severe cases. Isotretinoin is for severe nodulocystic acne."),
  np("AANP","Musculoskeletal",3,"A patient presents with a positive phalen test and tinel sign at the wrist. The NP should order:",["MRI of the wrist","Nerve conduction studies for confirmation","X-ray of the wrist","CBC and inflammatory markers"],1,"Positive Phalen and Tinel tests suggest carpal tunnel syndrome (median nerve compression). Nerve conduction studies/electromyography confirm the diagnosis and severity, guiding treatment decisions (conservative vs. surgical). X-rays do not evaluate nerve compression."),
  np("AANP","Musculoskeletal",2,"A patient with acute low back pain without red flags should be managed initially with:",["Immediate MRI","NSAIDs and continued normal activity","Strict bed rest for 2 weeks","Opioid analgesics as first-line"],1,"Acute low back pain without red flags (cauda equina, cancer, fracture, infection) is managed conservatively: NSAIDs, acetaminophen, continued activity (not bed rest), and self-care education. Imaging is not indicated in the first 4-6 weeks unless red flags are present."),
  np("NP-CAT","Musculoskeletal",3,"A patient with suspected rheumatoid arthritis should have which initial laboratory tests ordered?",["ANA only","RF, anti-CCP, ESR, and CRP","Uric acid and synovial fluid analysis","HLA-B27 and spinal imaging"],1,"RA workup includes RF (70% sensitive), anti-CCP (more specific at 95%), ESR, and CRP for inflammation. Anti-CCP positive with RF positive has highest specificity. X-rays of affected joints assess for erosive changes. Early referral to rheumatology is recommended."),
  np("AANP","Infectious Disease",3,"A patient with community-acquired pneumonia and comorbidities (COPD, diabetes) should be treated outpatient with:",["Amoxicillin alone","Respiratory fluoroquinolone OR amoxicillin-clavulanate + macrolide","First-generation cephalosporin","Metronidazole"],1,"For outpatients with CAP and comorbidities, ATS/IDSA 2019 recommends either a respiratory fluoroquinolone (moxifloxacin, levofloxacin) OR combination therapy with amoxicillin-clavulanate/cephalosporin PLUS a macrolide to cover typical and atypical organisms."),
  np("NP-CAT","Infectious Disease",3,"A patient diagnosed with latent TB infection (positive IGRA, negative chest X-ray) should be treated with:",["4-drug regimen (RIPE therapy)","3 months of isoniazid + rifapentine (3HP regimen) or 4 months of rifampin","No treatment needed for latent TB","Fluoroquinolone for 6 months"],1,"LTBI treatment prevents progression to active TB. Current preferred regimens include 3HP (isoniazid + rifapentine weekly x 12 doses), 4R (rifampin daily x 4 months), or 9H (isoniazid daily x 9 months). 3HP has best completion rates due to shorter duration."),
  np("AANP","Reproductive",3,"A 28-year-old woman with PCOS and anovulatory infertility desires pregnancy. First-line ovulation induction is:",["Clomiphene citrate or letrozole","Gonadotropin injections","In vitro fertilization","Metformin monotherapy"],0,"Letrozole has emerged as first-line for ovulation induction in PCOS (higher live birth rates than clomiphene in studies). Clomiphene citrate is also first-line. Metformin may be adjunctive but is not sufficient as monotherapy for fertility in most cases."),
  np("AANP","Geriatrics",3,"When evaluating an elderly patient with recurrent falls, the NP should perform:",["CT scan of the head only","Comprehensive falls assessment including orthostatic BP, vision, gait, medications, and home safety","Only a neurological examination","Psychiatric evaluation"],1,"Falls assessment in older adults is multifactorial: orthostatic vitals, visual acuity, gait and balance testing (Timed Up and Go), medication review (psychotropics, antihypertensives), cognitive assessment, home safety evaluation, and screening for peripheral neuropathy."),
  np("NP-CAT","Geriatrics",3,"A 80-year-old with multiple comorbidities has an HbA1c target that should be:",["< 6.5% to prevent all complications","< 8.0% to avoid hypoglycemia risk","< 7.0% as standard for all diabetics","< 5.7% to achieve normal glucose"],1,"ADA recommends less stringent HbA1c targets (< 8.0-8.5%) for older adults with limited life expectancy, multiple comorbidities, or high hypoglycemia risk. Tight control increases hypoglycemia risk, which causes falls, fractures, and cognitive impairment in elderly patients."),
  np("AANP","Hematological",3,"A patient with macrocytic anemia (MCV 112) should have which tests ordered?",["Iron studies and ferritin","Vitamin B12, folate, and reticulocyte count","Hemoglobin electrophoresis","Coagulation studies"],1,"Macrocytic anemia (MCV > 100) is most commonly caused by B12 or folate deficiency. Methylmalonic acid and homocysteine levels help differentiate: both elevated in B12 deficiency, only homocysteine elevated in folate deficiency. Reticulocyte count assesses marrow response."),
  np("AANP","Renal",3,"A patient with stage 3a CKD (GFR 52) and proteinuria should be started on:",["Hydrochlorothiazide for blood pressure","ACE inhibitor or ARB for renoprotection","Calcium channel blocker as first-line","Alpha-blocker for blood pressure"],1,"ACEIs/ARBs are first-line for CKD with proteinuria because they reduce intraglomerular pressure and proteinuria, slowing CKD progression. Target BP < 130/80. SGLT2 inhibitors should also be considered for additional renoprotection."),
  np("NP-CAT","Renal",3,"A patient with CKD stage 4 (GFR 22) has a hemoglobin of 9.2 g/dL. The NP should:",["Transfuse packed red blood cells immediately","Start erythropoiesis-stimulating agent (ESA) after ruling out iron deficiency","Prescribe oral iron only","Refer for bone marrow biopsy"],1,"Anemia of CKD results from decreased erythropoietin production. After ensuring adequate iron stores (ferritin > 100, TSAT > 20%), ESAs (epoetin alfa, darbepoetin) are initiated. Target hemoglobin is 10-11.5 g/dL; higher targets increase cardiovascular risk."),
  np("AANP","Women's Health",3,"A 50-year-old woman reports urinary incontinence with coughing and sneezing. This pattern suggests:",["Urge incontinence","Stress incontinence","Overflow incontinence","Functional incontinence"],1,"Stress incontinence is involuntary urine loss during physical activity that increases intra-abdominal pressure (coughing, sneezing, laughing, lifting). It results from weakened pelvic floor muscles. First-line treatment is pelvic floor muscle training (Kegel exercises)."),
  np("NP-CAT","Women's Health",3,"A patient presents for annual well-woman exam. According to current USPSTF guidelines, cervical cancer screening with Pap smear alone should begin at age:",["18","21","25","30"],1,"USPSTF recommends cervical cancer screening beginning at age 21 with Pap smear every 3 years. At age 30, options include Pap every 3 years, hrHPV testing every 5 years, or co-testing every 5 years. Screening ends at age 65 with adequate prior negative results."),
  np("AANP","Preventive Medicine",2,"According to USPSTF, lung cancer screening with low-dose CT is recommended for adults aged 50-80 who:",["Have any smoking history","Have a 20 pack-year history and currently smoke or quit within 15 years","Have a family history of lung cancer only","Have chronic cough"],1,"USPSTF 2021 expanded lung cancer screening: adults aged 50-80 with 20+ pack-year smoking history who currently smoke or quit within past 15 years. Annual LDCT screening. Previous criteria were age 55-80 and 30 pack-years."),
  np("NP-CAT","Preventive Medicine",2,"A 45-year-old male with no risk factors asks about colorectal cancer screening. The NP should recommend:",["Screening starting at age 50","Colonoscopy starting at age 45 per current guidelines","No screening until age 55","FIT testing starting at age 50 only"],1,"USPSTF 2021 lowered colorectal cancer screening to age 45 for average-risk adults. Options include colonoscopy every 10 years, FIT annually, FIT-DNA (Cologuard) every 1-3 years, CT colonography every 5 years, or flexible sigmoidoscopy every 5-10 years."),
  np("AANP","Cardiovascular",3,"A patient with newly diagnosed heart failure with preserved ejection fraction (HFpEF) should be managed with:",["ACE inhibitor and beta-blocker as standard HFrEF therapy","Diuretics for volume management, SGLT2 inhibitor, and addressing comorbidities","Digoxin as first-line therapy","Cardiac resynchronization therapy"],1,"HFpEF management focuses on symptom relief with diuretics, SGLT2 inhibitors (empagliflozin showed benefit in EMPEROR-Preserved trial), BP control, and managing comorbidities (obesity, AF, diabetes). Unlike HFrEF, neurohormonal agents have less evidence for HFpEF."),
  np("NP-CAT","Cardiovascular",3,"A patient with new-onset atrial fibrillation for less than 48 hours may be considered for:",["Only rate control without cardioversion attempt","Cardioversion without TEE if anticoagulation status is adequate","Long-term anticoagulation before any cardioversion","Permanent pacemaker placement"],1,"AF < 48 hours duration may be cardioverted without prior TEE if the patient is hemodynamically stable and not at high risk for LA thrombus. Anticoagulation should be initiated. If AF duration is uncertain or > 48 hours, TEE or 3 weeks of anticoagulation is required before cardioversion."),
  np("AANP","Endocrine",3,"A patient with a TSH of 0.1 and elevated free T4 is diagnosed with Graves disease. First-line treatment in the US is:",["Surgical thyroidectomy","Radioactive iodine ablation","Methimazole","Propranolol monotherapy"],2,"In the US, radioactive iodine has traditionally been first-line, but methimazole is increasingly used as initial therapy, especially for mild-moderate disease, pregnancy planning, or patients who prefer it. Methimazole is first-line for Graves in many other countries."),
  np("AANP","Neurological",3,"A patient with chronic daily headache using OTC analgesics more than 15 days per month likely has:",["Cluster headache","Medication overuse headache","Tension-type headache","Migraine with aura"],1,"Medication overuse headache (MOH) develops when acute headache medications are used > 10-15 days/month for > 3 months. Treatment requires gradual withdrawal of the overused medication, bridge therapy for withdrawal headaches, and preventive medication initiation."),
  np("NP-CAT","Neurological",3,"A patient presents with sudden severe headache described as 'the worst headache of my life.' The NP should immediately:",["Prescribe sumatriptan and follow up in 1 week","Order emergent CT head without contrast, followed by LP if CT is negative","Prescribe a stronger analgesic","Schedule an outpatient MRI within 2 weeks"],1,"Thunderclap headache ('worst headache of my life') requires emergent evaluation for subarachnoid hemorrhage. CT head detects 95-98% of SAH within 6 hours. If CT is negative, lumbar puncture looking for xanthochromia is required to rule out SAH."),
  np("AANP","Pharmacology",3,"A patient on carbamazepine for trigeminal neuralgia should have which test monitored?",["Thyroid function","CBC for aplastic anemia and agranulocytosis, plus sodium levels","Lipid panel","Renal function only"],1,"Carbamazepine can cause aplastic anemia, agranulocytosis (rare but fatal), and SIADH causing hyponatremia. Regular CBC and sodium monitoring are essential. Drug interactions are extensive due to CYP3A4 induction. HLA-B*1502 testing is recommended in high-risk populations for SJS/TEN."),
  np("NP-CAT","Pharmacology",3,"When prescribing trimethoprim-sulfamethoxazole, the NP should avoid concurrent use with:",["Acetaminophen","Warfarin (increases INR significantly)","Omeprazole","Aspirin"],1,"TMP-SMX significantly inhibits CYP2C9, the primary enzyme metabolizing warfarin. This interaction can double or triple the INR, causing dangerous bleeding. Close INR monitoring or dose reduction is required. TMP also increases methotrexate and phenytoin levels."),
  np("AANP","Mental Health",2,"The PHQ-9 score for a patient is 16. This indicates:",["Minimal depression","Mild depression","Moderately severe depression","Severe depression"],2,"PHQ-9 scoring: 0-4 minimal, 5-9 mild, 10-14 moderate, 15-19 moderately severe, 20-27 severe depression. A score of 16 falls in the moderately severe range, warranting pharmacotherapy and/or psychotherapy with close follow-up."),
  np("AANP","Infectious Disease",2,"A patient with an uncomplicated skin abscess greater than 2 cm should be managed with:",["Oral antibiotics alone without drainage","Incision and drainage with consideration of antibiotics","Topical antibiotics only","Warm compresses for 4 weeks"],1,"I&D is the primary treatment for skin abscesses. Per IDSA guidelines, antibiotics (TMP-SMX or doxycycline for MRSA coverage) should be added for abscesses > 2 cm, surrounding cellulitis, immunocompromise, or systemic symptoms."),
  np("NP-CAT","Infectious Disease",3,"A patient with recurrent UTIs (3 per year) should be evaluated for:",["Immediate cystoscopy","Underlying risk factors and considered for prophylactic strategies","Long-term broad-spectrum antibiotic use","Surgical intervention"],1,"Recurrent UTI evaluation includes identifying modifiable risk factors (behavioral, anatomic), urine culture for organism/resistance patterns, and prophylactic strategies: post-coital prophylaxis, vaginal estrogen for postmenopausal women, or low-dose nightly antibiotics."),
  np("AANP","Reproductive",2,"A patient taking combined hormonal contraception should stop the medication and seek care if they experience:",["Mild breast tenderness","Severe headache with visual changes","Mild nausea during the first month","Spotting between periods"],1,"ACHES mnemonic for danger signs: Abdominal pain (hepatic adenoma), Chest pain (PE), Headache with visual changes (stroke), Eye problems (visual changes, loss), Severe leg pain (DVT). These require immediate evaluation and discontinuation of hormonal contraception."),
  np("NP-CAT","Reproductive",3,"A couple presents with infertility for 12 months. Initial evaluation of the female partner should include:",["Immediate IVF referral","Day 3 FSH and estradiol, TSH, prolactin, and hysterosalpingogram","Exploratory laparoscopy","Karyotype analysis"],1,"Female infertility workup includes ovarian reserve testing (day 3 FSH, estradiol, AMH), ovulatory assessment, thyroid function, prolactin, and tubal patency evaluation (HSG). Male partner requires semen analysis. Laparoscopy is not first-line."),
  np("AANP","Geriatrics",2,"The NP should screen all patients age 65+ for:",["Hepatitis C annually","Depression, cognitive impairment, and fall risk","STI screening annually","Sleep apnea with polysomnography"],1,"Routine geriatric screening includes depression (PHQ-2/9), cognitive assessment (MoCA/Mini-Cog), fall risk evaluation, hearing/vision screening, functional status, and medication review. These screenings identify treatable conditions that significantly impact quality of life."),
  np("NP-CAT","Geriatrics",3,"Delirium in hospitalized elderly patients is best distinguished from dementia by:",["The type of cognitive impairment","Acute onset with fluctuating course and inattention","Gradual onset with stable course","Family history of cognitive decline"],1,"Delirium features ACUTE onset (hours to days), fluctuating consciousness, inattention, and identifiable trigger. Dementia has GRADUAL onset (months to years), stable course, preserved attention initially, and progressive deterioration. Delirium can be superimposed on dementia."),
  np("AANP","Hematological",3,"A patient with newly diagnosed iron deficiency anemia should have which evaluation to determine the cause?",["Repeat CBC in 1 month","Evaluation for GI blood loss (colonoscopy for age >= 45) and menstrual history","Bone marrow biopsy","Hemoglobin electrophoresis"],1,"Iron deficiency in adults requires identification of the cause. In premenopausal women, menstrual losses are common. In men and postmenopausal women, GI blood loss (occult malignancy) must be excluded with colonoscopy and/or upper endoscopy. Celiac screening may also be appropriate."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < ALL.length; i += batchSize) {
    const batch = ALL.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[Bulk] Inserted ${inserted}/${ALL.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
